// Compute week range: previous Monday 00:00 UTC to Sunday 23:59:59 UTC
const now = new Date();
const day = now.getUTCDay(); // 0=Sun, 1=Mon, ...

// Find this Monday
const thisMonday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const diff = day === 0 ? 6 : day - 1;
thisMonday.setUTCDate(thisMonday.getUTCDate() - diff);

// Previous Monday is 7 days before this Monday
const prevMonday = new Date(thisMonday);
prevMonday.setUTCDate(prevMonday.getUTCDate() - 7);

// Sunday is 6 days after previous Monday
const prevSunday = new Date(prevMonday);
prevSunday.setUTCDate(prevSunday.getUTCDate() + 6);

const weekStart = prevMonday.toISOString().slice(0, 10);
const weekEnd = prevSunday.toISOString().slice(0, 10);

return [{ json: { week_start: weekStart, week_end: weekEnd } }];

// Score + Select Top Signals v4 (with all 11 signal types including experiment)
// Includes: messaging, narrative, icp, horizon, objection, pricing, proof, distribution, hiring, launch_decay, experiment
// Max per section varies by ship, max 45 total

const signals = $input.all().map(item => item.json);
const weekRange = $('Compute Week Range').first().json;

// Configuration: per-ship caps (from Control Plane v2 implementation plan Phase 6)
const SHIP_CAPS = {
  // Original ships
  messaging: 8,
  narrative: 5,
  icp: 5,
  horizon: 3,
  objection: 5,
  // New ships from Phase 2-3
  pricing: 4,
  proof: 3,
  distribution: 3,
  hiring: 2,
  launch_decay: 2,
  // Experiment surveillance
  experiment: 5
};

const MAX_PER_SECTION = 6;
const MAX_TOTAL = 45;

// Scoring weights
const WEIGHTS = {
  severity: 8,      // 1-5 severity * 8 = 0-40 points
  recency: 30,      // max 30 points, decays over 7 days
  confidence: 15,   // 0-1 confidence * 15 = 0-15 points
  source_quality: 15 // high=15, medium=10, low=5
};

// Compute actual score for a signal
function computeScore(signal) {
  const now = new Date();
  const createdAt = new Date(signal.created_at);
  const daysOld = (now - createdAt) / (1000 * 60 * 60 * 24);

  // Severity weight (0-40 points)
  const severityScore = (signal.severity || 3) * WEIGHTS.severity;

  // Recency weight (decays over 7 days)
  const recencyScore = Math.max(0, WEIGHTS.recency - (daysOld * 4.3));

  // Confidence weight (0-15 points)
  const confidenceScore = (parseFloat(signal.confidence) || 0.5) * WEIGHTS.confidence;

  // Source quality weight
  const sourceQuality = signal.source_quality || 'medium';
  const sourceScore = sourceQuality === 'high' ? 15 : sourceQuality === 'medium' ? 10 : 5;

  // Experiment signals get a boost based on combined_score from surveillance
  let experimentBoost = 0;
  if (signal.signal_type === 'experiment' && signal.meta?.combined_score) {
    experimentBoost = Math.min(signal.meta.combined_score * 0.5, 20);
  }

  return Math.round((severityScore + recencyScore + confidenceScore + sourceScore + experimentBoost) * 100) / 100;
}

// Infer decision_type based on signal type and content
function inferDecisionType(signal) {
  const signalType = signal.signal_type;
  const title = (signal.title || '').toLowerCase();
  const summary = (signal.summary || '').toLowerCase();

  // Original ships
  if (signalType === 'messaging') {
    if (title.includes('pricing') || summary.includes('pricing')) return 'packaging';
    if (title.includes('compet') || summary.includes('compet')) return 'positioning';
    return 'positioning';
  }
  if (signalType === 'narrative') {
    if (title.includes('risk') || summary.includes('risk')) return 'risk';
    return 'positioning';
  }
  if (signalType === 'icp') {
    if (title.includes('churn') || summary.includes('churn')) return 'risk';
    if (title.includes('expand') || summary.includes('expand')) return 'distribution';
    return 'distribution';
  }
  if (signalType === 'horizon') {
    if (title.includes('threat') || summary.includes('threat')) return 'risk';
    return 'proof';
  }
  if (signalType === 'objection') {
    if (title.includes('pricing') || summary.includes('price')) return 'packaging';
    if (title.includes('compet') || summary.includes('alternative')) return 'positioning';
    return 'enablement';
  }

  // New ships from Phase 2-3
  if (signalType === 'pricing') {
    return 'packaging';
  }
  if (signalType === 'proof') {
    return 'proof';
  }
  if (signalType === 'distribution') {
    return 'distribution';
  }
  if (signalType === 'hiring') {
    return 'risk'; // Competitive intelligence
  }
  if (signalType === 'launch_decay') {
    return 'positioning';
  }

  // Experiment surveillance
  if (signalType === 'experiment') {
    // Use category from meta if available
    const category = signal.meta?.pattern_category || signal.decision_type;
    if (category === 'packaging') return 'packaging';
    if (category === 'proof') return 'proof';
    if (category === 'distribution') return 'distribution';
    if (category === 'strategy') return 'risk';
    return 'positioning';
  }

  return 'enablement';
}

// Infer recommended_asset based on decision_type
function inferRecommendedAsset(decisionType) {
  const mapping = {
    positioning: 'homepage',
    packaging: 'pricing',
    distribution: 'deck',
    proof: 'talk_track',
    enablement: 'talk_track',
    risk: 'deck',
    hiring: 'battlecard'
  };
  return mapping[decisionType] || 'none';
}

// Infer owner_team based on decision_type
function inferOwnerTeam(decisionType) {
  const mapping = {
    positioning: 'PMM',
    packaging: 'PMM',
    distribution: 'sales',
    proof: 'PMM',
    enablement: 'sales',
    risk: 'exec',
    hiring: 'exec'
  };
  return mapping[decisionType] || 'PMM';
}

// Infer time_sensitivity based on severity
function inferTimeSensitivity(severity) {
  if (severity >= 4) return 'now';
  if (severity >= 3) return 'this_week';
  return 'monitor';
}

// Process each signal: compute score and action mapping
const enrichedSignals = signals.map(signal => {
  const score = computeScore(signal);
  const decisionType = inferDecisionType(signal);

  return {
    ...signal,
    score: score,
    promo_score: score,
    decision_type: decisionType,
    recommended_asset: inferRecommendedAsset(decisionType),
    owner_team: inferOwnerTeam(decisionType),
    time_sensitivity: inferTimeSensitivity(signal.severity || 3),
    summary_short: signal.summary ? signal.summary.substring(0, 100) + (signal.summary.length > 100 ? '...' : '') : ''
  };
});

// All sections including experiment
const sections = [
  'messaging', 'narrative', 'icp', 'horizon', 'objection',
  'pricing', 'proof', 'distribution', 'hiring', 'launch_decay',
  'experiment'
];

const selectedBySection = {};
let totalSelected = [];

for (const section of sections) {
  const cap = SHIP_CAPS[section] || MAX_PER_SECTION;

  // Get signals for this section, sort by score descending
  const sectionSignals = enrichedSignals
    .filter(s => s.signal_type === section)
    .sort((a, b) => b.score - a.score)
    .slice(0, cap);

  selectedBySection[section] = sectionSignals;
  totalSelected = totalSelected.concat(sectionSignals);
}

// Enforce total cap (keep highest scores)
if (totalSelected.length > MAX_TOTAL) {
  totalSelected.sort((a, b) => b.score - a.score);
  totalSelected = totalSelected.slice(0, MAX_TOTAL);
}

// Build signal summaries for Anthropic prompt
const signalSummaries = {};
for (const section of sections) {
  signalSummaries[section] = (selectedBySection[section] || []).map(s => ({
    id: s.id,
    severity: s.severity,
    title: s.title,
    summary_short: s.summary_short,
    score: s.score,
    decision_type: s.decision_type,
    time_sensitivity: s.time_sensitivity,
    // Include experiment-specific fields
    ...(s.signal_type === 'experiment' ? {
      survivorship_score: s.meta?.survivorship_score,
      propagation_score: s.meta?.propagation_score,
      companies: s.meta?.companies
    } : {})
  }));
}

// Build action mapping summary for prompt
const actionSummary = {
  positioning: totalSelected.filter(s => s.decision_type === 'positioning').length,
  packaging: totalSelected.filter(s => s.decision_type === 'packaging').length,
  distribution: totalSelected.filter(s => s.decision_type === 'distribution').length,
  proof: totalSelected.filter(s => s.decision_type === 'proof').length,
  enablement: totalSelected.filter(s => s.decision_type === 'enablement').length,
  risk: totalSelected.filter(s => s.decision_type === 'risk').length,
  urgent_count: totalSelected.filter(s => s.time_sensitivity === 'now').length,
  this_week_count: totalSelected.filter(s => s.time_sensitivity === 'this_week').length
};

// Build system prompt with strict JSON schema (updated for all signal types including experiment)
const systemPrompt = `You are a GTM intelligence analyst creating weekly packets for a PMM team. Synthesize signals into actionable intelligence.

SIGNAL CATEGORIES:
- messaging: Homepage and positioning changes
- narrative: Market narrative shifts
- icp: Target audience signals
- horizon: Platform and market shifts
- objection: Customer objections and concerns
- pricing: Pricing and packaging changes
- proof: Trust signals and social proof
- distribution: Integration and partnership moves
- hiring: Hiring signals indicating strategy
- launch_decay: Post-launch momentum tracking
- experiment: Market-wide pattern winners (proven and emerging)

CRITICAL: Output STRICT JSON only. No markdown, no explanations outside the JSON.

Required JSON schema:
{
  "packet_title": "string (Week of YYYY-MM-DD: descriptive title)",
  "exec_summary": ["string (max 7 bullets, each under 100 chars)"],
  "sections": {
    "messaging": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "narrative": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "icp": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "horizon": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "objection": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "pricing": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "proof": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "distribution": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "hiring": {"summary": "string", "highlights": ["string"], "action_items": ["string"]},
    "launch_decay": {"summary": "string", "highlights": ["string"], "action_items": ["string"]}
  },
  "market_winners": {
    "proven": [
      {
        "pattern_label": "string",
        "what_changed": "string (1 line)",
        "where_seen": ["company names"],
        "survival_weeks": number,
        "why_it_matters": "string",
        "implementation_guidance": "string"
      }
    ],
    "emerging": [
      {
        "pattern_label": "string",
        "what_changed": "string",
        "where_seen": ["company names"],
        "why_it_matters": "string"
      }
    ]
  },
  "key_questions": ["string (3-5 strategic questions)"],
  "predictions": [
    {
      "hypothesis": "string (testable prediction)",
      "what_to_watch": "string (evidence to track)",
      "signal_ids": ["uuid"],
      "confidence": "low|medium|high",
      "timeframe": "string (e.g., 'next 2 weeks')"
    }
  ],
  "action_mapping": {
    "this_week": [{"action": "string", "owner": "PMM|sales|CS|product|exec", "asset": "string"}],
    "monitor": ["string (things to track)"]
  },
  "bets": [
    {
      "hypothesis": "string",
      "signal_ids": ["uuid"],
      "confidence": "low|medium|high"
    }
  ]
}

CONSTRAINTS:
- exec_summary: max 7 bullets
- predictions: 2-5 items, must be testable hypotheses
- bets: max 3 items
- All signal_ids must be valid UUIDs from the input
- For sections with no signals, use {"summary": "No signals this week", "highlights": [], "action_items": []}
- market_winners: synthesize experiment signals into actionable patterns
  - proven: max 3 patterns with high survivorship
  - emerging: max 3 patterns gaining traction`;

// Build user content with all signal types
const userContent = `Week: ${weekRange.week_start} to ${weekRange.week_end}
Total signals loaded: ${signals.length}
Selected for packet: ${totalSelected.length}

ACTION MAPPING SUMMARY:
- Positioning signals: ${actionSummary.positioning}
- Packaging signals: ${actionSummary.packaging}
- Distribution signals: ${actionSummary.distribution}
- Proof signals: ${actionSummary.proof}
- Enablement signals: ${actionSummary.enablement}
- Risk signals: ${actionSummary.risk}
- URGENT (act now): ${actionSummary.urgent_count}
- This week priority: ${actionSummary.this_week_count}

MESSAGING SIGNALS (${signalSummaries.messaging.length}):
${JSON.stringify(signalSummaries.messaging, null, 2)}

NARRATIVE SIGNALS (${signalSummaries.narrative.length}):
${JSON.stringify(signalSummaries.narrative, null, 2)}

ICP SIGNALS (${signalSummaries.icp.length}):
${JSON.stringify(signalSummaries.icp, null, 2)}

HORIZON SIGNALS (${signalSummaries.horizon.length}):
${JSON.stringify(signalSummaries.horizon, null, 2)}

OBJECTION SIGNALS (${signalSummaries.objection.length}):
${JSON.stringify(signalSummaries.objection, null, 2)}

PRICING SIGNALS (${signalSummaries.pricing.length}):
${JSON.stringify(signalSummaries.pricing, null, 2)}

PROOF SIGNALS (${signalSummaries.proof.length}):
${JSON.stringify(signalSummaries.proof, null, 2)}

DISTRIBUTION SIGNALS (${signalSummaries.distribution.length}):
${JSON.stringify(signalSummaries.distribution, null, 2)}

HIRING SIGNALS (${signalSummaries.hiring.length}):
${JSON.stringify(signalSummaries.hiring, null, 2)}

LAUNCH DECAY SIGNALS (${signalSummaries.launch_decay.length}):
${JSON.stringify(signalSummaries.launch_decay, null, 2)}

EXPERIMENT SIGNALS (Market Winners) (${signalSummaries.experiment.length}):
${JSON.stringify(signalSummaries.experiment, null, 2)}

Generate weekly GTM intelligence packet with predictions, action mapping, and Market Winners section.`;

// Build Anthropic API body
const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 5000,
  temperature: 0.3,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    week_start: weekRange.week_start,
    week_end: weekRange.week_end,
    total_signals: signals.length,
    selected_count: totalSelected.length,
    selected_signals: totalSelected,
    signal_summaries: signalSummaries,
    action_summary: actionSummary,
    anthropic_body: anthropicBody
  }
}];

// Parse Packet JSON v3 (with predictions + action_mapping fallback + SQL escaping)
// Handles Anthropic response and extracts structured packet data

const anthropicResponse = $input.first().json;
const weekData = $('Score + Select Top Signals').first().json;

// Extract the text content from Anthropic response
let responseText = '';
if (anthropicResponse.content && anthropicResponse.content[0]) {
  responseText = anthropicResponse.content[0].text || '';
} else if (typeof anthropicResponse === 'string') {
  responseText = anthropicResponse;
}

// Clean up potential markdown code fences
responseText = responseText.trim();
if (responseText.startsWith('```json')) {
  responseText = responseText.slice(7);
}
if (responseText.startsWith('```')) {
  responseText = responseText.slice(3);
}
if (responseText.endsWith('```')) {
  responseText = responseText.slice(0, -3);
}
responseText = responseText.trim();

// Parse the JSON
let packet;
const jsonMatch = responseText.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  try {
    packet = JSON.parse(jsonMatch[0]);
  } catch (e) {
    throw new Error('Failed to parse packet JSON: ' + e.message);
  }
}

// Ensure required fields with fallbacks
const parsedPacket = {
  packet_title: packet.packet_title || `Week of ${weekData.week_start}: GTM Intelligence Packet`,
  exec_summary: Array.isArray(packet.exec_summary) ? packet.exec_summary.slice(0, 7) : [],
  sections: {
    messaging: packet.sections?.messaging || { summary: '', highlights: [], action_items: [] },
    narrative: packet.sections?.narrative || { summary: '', highlights: [], action_items: [] },
    icp: packet.sections?.icp || { summary: '', highlights: [], action_items: [] },
    horizon: packet.sections?.horizon || { summary: '', highlights: [], action_items: [] },
    objection: packet.sections?.objection || { summary: '', highlights: [], action_items: [] }
  },
  key_questions: Array.isArray(packet.key_questions) ? packet.key_questions.slice(0, 5) : [],
  bets: Array.isArray(packet.bets) ? packet.bets.slice(0, 3) : [],
  predictions: Array.isArray(packet.predictions) ? packet.predictions.slice(0, 5) : [],
  action_mapping: packet.action_mapping || { this_week: [], monitor: [] },
  market_winners: packet.market_winners || { proven: [], emerging: [] }
};

// Helper function to escape a string for PostgreSQL SQL literals
function escapeForPg(str) {
  if (str === null || str === undefined) return '';
  return String(str)
    .replace(/\\/g, '\\\\')
    .replace(/'/g, "''");
}

// Helper to escape JSON for PostgreSQL jsonb column
function escapeJsonForPg(obj) {
  const jsonStr = JSON.stringify(obj);
  return escapeForPg(jsonStr);
}

// Return with both original packet data AND pre-escaped versions for SQL
return [{
  json: {
    week_start: weekData.week_start,
    week_end: weekData.week_end,
    packet: parsedPacket,
    packet_title_escaped: escapeForPg(parsedPacket.packet_title),
    exec_summary_escaped: parsedPacket.exec_summary.map(s => escapeForPg(s)),
    sections_escaped: escapeJsonForPg(parsedPacket.sections),
    key_questions_escaped: parsedPacket.key_questions.map(q => escapeForPg(q)),
    bets_escaped: escapeJsonForPg(parsedPacket.bets),
    predictions_escaped: escapeJsonForPg(parsedPacket.predictions),
    action_mapping_escaped: escapeJsonForPg(parsedPacket.action_mapping),
    selected_signals: weekData.selected_signals,
    action_summary: weekData.action_summary,
    total_signals: weekData.total_signals,
    selected_count: weekData.selected_count
  }
}];

// Prepare packet_items for insertion
const packetId = $('Upsert Packet').first().json.id;
const selectData = $('Parse Packet JSON').first().json;

const items = selectData.selected_signals.map((signal, idx) => ({
  packet_id: packetId,
  signal_id: signal.id,
  section: signal.signal_type,
  rank: idx + 1,
  score: signal.score
}));

return items.map(item => ({ json: item }));

// Builder 1: Living Objection Library
// Uses n8n cross-node references to pull data from upstream nodes
// Output: Versioned objection library markdown
// Hard caps: max 12 objections, max 2 evidence links per objection in main view

// Reference data from previous nodes using n8n syntax
const weekRange = $('Compute Week Range').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;

// Get signals (filtered to messaging, narrative, icp - most relevant for objections)
const signals = scoreResult.selected_signals.filter(s =>
  ['messaging', 'narrative', 'icp'].includes(s.signal_type)
);

// Configuration
const MAX_OBJECTIONS = 12;
const MAX_EVIDENCE_PER_OBJECTION = 2;

// Categories for taxonomy
const OBJECTION_CATEGORIES = [
  'price_value',      // "Too expensive", "ROI unclear"
  'timing',           // "Not now", "Just renewed competitor"
  'complexity',       // "Too complex", "Don't have resources"
  'risk',             // "Security concerns", "Vendor stability"
  'fit',              // "Not right for us", "Missing features"
  'competition',      // "Competitor does X better"
  'inertia'           // "Current solution works fine", "Change is hard"
];

// Build system prompt for Anthropic
const systemPrompt = `You are a sales enablement expert building an Objection Library from GTM signals.

CRITICAL: Output STRICT JSON only.

Schema:
{
  "objections": [
    {
      "category": "price_value|timing|complexity|risk|fit|competition|inertia",
      "objection_text": "string (the objection as a buyer would say it)",
      "frequency": "high|medium|low",
      "personas": ["string (personas who raise this)"],
      "segments": ["string (segments where common)"],
      "evidence_urls": ["string (max ${MAX_EVIDENCE_PER_OBJECTION})"],
      "rebuttal": {
        "acknowledge": "string (validate the concern)",
        "reframe": "string (shift perspective)",
        "proof": "string (evidence to cite)",
        "talk_track": "string (suggested response)"
      },
      "signal_ids": ["uuid (source signals)"],
      "is_new_this_week": true|false
    }
  ],
  "summary": {
    "total_objections": number,
    "top_category": "string",
    "new_this_week": number,
    "trending_up": ["string (objections growing)"],
    "trending_down": ["string (objections fading)"]
  }
}

CONSTRAINTS:
- Max ${MAX_OBJECTIONS} objections
- Max ${MAX_EVIDENCE_PER_OBJECTION} evidence URLs per objection
- Each objection must have at least one signal_id as evidence
- Rebuttals must be specific and actionable, not generic
- Mark objections as new_this_week if they appear for first time`;

// Build user content with signals
const userContent = `Week: ${weekStart} to ${weekEnd}
Packet ID: ${packetId}

Build an Objection Library from these signals:

SIGNALS (${signals.length} total):
${JSON.stringify(signals.map(s => ({
  id: s.id,
  type: s.signal_type,
  severity: s.severity,
  title: s.title,
  summary: s.summary,
  evidence_urls: s.evidence_urls || []
})), null, 2)}

Extract objections mentioned or implied in these signals. Group by category, provide evidence-linked rebuttals.`;

// Build Anthropic API body
const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 2500,
  temperature: 0.2,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    builder_type: 'objection_library',
    week_start: weekStart,
    week_end: weekEnd,
    packet_id: packetId,
    input_signal_count: signals.length,
    input_signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

// Parse Objection Library response from Anthropic
// Input: Anthropic API response
// Output: Parsed objection library data ready for database insert

const anthropicResponse = $input.first().json;
const builderData = $('Builder: Objection Library').first().json;

// Extract the JSON content from Anthropic response
const content = anthropicResponse.content[0].text;

// Parse the JSON
let objectionLibrary;
try {
  objectionLibrary = JSON.parse(content);
} catch (e) {
  // If parsing fails, try to extract JSON from markdown code blocks
  const jsonMatch = content.match(/```json?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    objectionLibrary = JSON.parse(jsonMatch[1]);
  } else {
    throw new Error('Failed to parse Anthropic response as JSON');
  }
}

// Validate required fields
if (!objectionLibrary.objections || !Array.isArray(objectionLibrary.objections)) {
  objectionLibrary.objections = [];
}

if (!objectionLibrary.summary) {
  objectionLibrary.summary = {
    total_objections: objectionLibrary.objections.length,
    top_category: objectionLibrary.objections[0]?.category || 'unknown',
    new_this_week: objectionLibrary.objections.filter(o => o.is_new_this_week).length,
    trending_up: [],
    trending_down: []
  };
}

// Build the output for database insert
return [{
  json: {
    week_start: builderData.week_start,
    week_end: builderData.week_end,
    packet_id: builderData.packet_id,
    content_json: objectionLibrary,
    content_md: JSON.stringify(objectionLibrary, null, 2),
    included_signal_ids: builderData.input_signal_ids,
    objection_count: objectionLibrary.objections.length
  }
}];

// Builder 2: Buyer Swipe File (language that grows)
// Uses n8n cross-node references to pull data from upstream nodes
// Output: Versioned swipe file markdown with persona-tagged phrases
// Hard caps: max 30 phrases total, max 5 per persona

// Reference data from previous nodes using n8n syntax
const weekRange = $('Compute Week Range').first().json;
const packetResult = $('Upsert Packet').first().json;
const scoreResult = $('Score + Select Top Signals').first().json;

const weekStart = weekRange.week_start;
const weekEnd = weekRange.week_end;
const packetId = packetResult.id;

// Get all signals (swipe file uses all types for buyer language)
const signals = scoreResult.selected_signals;

// Define phrase categories for extraction
const PHRASE_CATEGORIES = [
  'pain_points',
  'desired_outcomes',
  'objections',
  'trigger_events',
  'evaluation_criteria',
  'competitive_mentions',
  'budget_signals',
  'timeline_indicators'
];

// Build the system prompt - MUST use backticks with unescaped quotes
